```typescript
// FILE CONTENT BEGIN
import React from 'react';
import { Button } from '@material-ui/core';
import { useTranslation } from 'react-i18next';
import { makeStyles } from '@material-ui/core/styles';

interface TaskActionsProps {
  task: Task;
  onToggleBlock: (taskId: string) => void;
  isAdmin: boolean;
  isManualBlocked: boolean;
  isAuditInProgress: boolean;
  canManageTasks: boolean;
}

const useStyles = makeStyles((theme) => ({
  actionsContainer: {
    display: 'flex',
    justifyContent: 'flex-end',
    marginTop: theme.spacing(1),
  },
  actionButton: {
    marginLeft: theme.spacing(1),
  },
}));

const TaskActions: React.FC<TaskActionsProps> = ({
  task,
  onToggleBlock,
  isAdmin,
  isManualBlocked,
  isAuditInProgress,
  canManageTasks,
}) => {
  const { t } = useTranslation();
  const classes = useStyles();

  const isBlocked = !!task.data().isBlocked; // Safe check against potential undefined value

  const perm_btn_lock = canManageTasks; // Permission to block

  return (
    <div className={classes.actionsContainer}>
      {perm_btn_lock && !isManualBlocked && !isAuditInProgress && (
        <Button
          className={classes.actionButton}
          color="primary"
          variant="contained"
          onClick={() => onToggleBlock(task.id)}
        >
          {t(isBlocked ? 'unlock_task' : 'lock_task')}
        </Button>
      )}
      {/* ... other buttons ... */}
    </div>
  );
};

export default TaskActions;
// FILE CONTENT END
```


